},{"id":"1780585191989-NOV_0502.JPG","url":"https://nxyeqjyxwzaveltsyszx.supabase.co/storage/v1/object/public/event-media/1780585189926-u00iag-NOV_0502.JPG","name":"NOV_0502.JPG","path":"1780585189926-u00iag-NOV_0502.JPG","type":"image"},{"id":"1780585195007-NOV_0507.JPG","url":"https://nxyeqjyxwzaveltsyszx.supabase.co/storage/v1/object/public/event-media/1780585192320-lxgusu-NOV_0507.JPG","name":"NOV_0507.JPG","path":"1780585192320-lxgusu-NOV_0507.JPG","type":"image"},{"id":"1780591834700-NOV_0448.JPG","url":"https://nxyeqjyxwzaveltsyszx.supabase.co/storage/v1/object/public/event-media/1780591830932-ct1wpq-NOV_0448.JPG","name":"NOV_0448.JPG","path":"1780591830932-ct1wpq-NOV_0448.JPG","type":"image"},{"id":"1780591837018-NOV_0442.JPG","url":"https://nxyeqjyxwzaveltsyszx.supabase.co/storage/v1/object/public/event-media/1780591834761-wst0kz-NOV_0442.JPG","name":"NOV_0442.JPG","path":"1780591834761-wst0kz-NOV_0442.JPG","type":"image"},{"id":"1780591930565-NOV_0453.JPG","url":"https://nxyeqjyxwzaveltsyszx.supabase.co/storage/v1/object/public/event-media/1780591926927-ul48ma-NOV_0453.JPG","name":"NOV_0453.JPG","path":"1780591926927-ul48ma-NOV_0453.JPG","type":"image"},{"id":"1780591932741-NOV_0448.JPG","url":"https://nxyeqjyxwzaveltsyszx.supabase.co/storage/v1/object/public/event-media/1780591930643-66zws8-NOV_0448.JPG","name":"NOV_0448.JPG","path":"1780591930643-66zws8-NOV_0448.JPG","type":"image"},{"id":"1780591934975-NOV_0442.JPG","url":"https://nxyeqjyxwzaveltsyszx.supabase.co/storage/v1/object/public/event-media/1780591932776-ikt8pk-NOV_0442.JPG","name":"NOV_0442.JPG","path":"1780591932776-ikt8pk-NOV_0442.JPG","type":"image"}],"title":"2025 - Pierre-Blaise Family Reunion","location":"Marlene and Marcien''s Residence","description":"A great thanks to our mentor, Jean-Marie Pierre, whose guidance and support helped make this memorable reunion possible.\nThe family finally reunited after a very long time, and it was heartwarming to see so many of us mingling, reconnecting, and sharing memories together."}'::jsonb);

-- Jean-Marie Pierre tribute (stored as a marked row in events)
insert into public.events (data) values ('{"lead":"With dedication, patience, and vision, Jean-Marie Pierre gathered and preserved the story of our family, giving us a priceless gift that strengthens our identity and keeps our legacy alive for generations to come.","photo":"","accolades":"Researched and assembled the Pierre-Blaise family tree across multiple generations.\nPreserved photographs, names, and memories that might otherwise have been lost.\nBrought the family together for our reunion through his tireless work.","upbringing":"Jean-Marie Pierre was born on February 3, 1948, in Arcahaie, Haiti, where he grew up with a deep respect for education and hard work. From his earliest school days through his years at Lycée Louverture, he distinguished himself through discipline and determination, eventually earning both Baccalauréat I and Baccalauréat II, the highest levels of secondary certification in the country.\n\nHis first professional steps were at Contribution, Haiti’s tax collection office, where he worked for three years. But in 1974, with courage and hope, he left Haiti for the United States. Like many immigrants, he began with humble jobs, working wherever opportunity appeared. He never stopped learning, taking classes while working full time, determined to build a better future.\n\nHis persistence paid off. Jean-Marie completed a four year laboratory program, trained in hospital settings, and became a laboratory technologist specializing in hematology. For 24 years, he served patients and trained new staff, earning respect for his skill, reliability, and leadership.\n\nEducation remained close to his heart. He spent many years as a teaching aide, guiding young children and supporting their growth. His gentle patience and steady presence made him a beloved figure in the classroom.\n\nAfter retiring at the age of 62, Jean-Marie continue to devote himself to preserving family history. He became the guardian of the family tree, gathering names, dates, stories, and memories so future generations would know where they came from.\n\nHis dedication has brought our history to life in a way that connects generations and strengthens our sense of identity. Now living in Brooklyn, NY with his wife Lucienne, Jean-Marie is a proud father and grandfather whose commitment to our family’s story has given us a priceless legacy. His efforts made these family reunions not just possible, but deeply meaningful for all of us.\n\nHis life is a story of resilience, service, and love for family.\n\n\n","_contentKey":"jeanmarie"}'::jsonb);

commit;
